360→function ExtensionsTab({
361→  extensions,
362→  onToggle,
363→  query,
364→}: {
365→  extensions: ExtensionEntry[];
366→  onToggle: (id: string) => void;
367→  query: string;
368→}) {
369→  const filtered = useMemo(() => {
370→    if (!query) return extensions;
371→    const lower = query.toLowerCase();
372→    return extensions.filter(
373→      ext =>
374→        ext.name.toLowerCase().includes(lower) ||
375→        ext.description.toLowerCase().includes(lower) ||
376→        ext.author.toLowerCase().includes(lower),
377→    );
378→  }, [
379→    extensions,
380→    query,
381→  ]);
382→
383→  const raycastExts = filtered.filter(ext => ext.author === 'Raycast');
384→  const communityExts = filtered.filter(ext => ext.author !== 'Raycast');
385→
386→  return (
387→    <div className="settings-view__extensions">
388→      {filtered.length === 0 ? (
389→        <EmptyState
390→          icon={<SearchEmptyIcon />}
391→          title="No Extensions Found"
392→          description="Try a different search term"
393→        />
394→      ) : (
395→        <>
396→          {raycastExts.length > 0 && (
397→            <div className="settings-section">
398→              <div className="settings-section__title">Built-in</div>
399→              {raycastExts.map(ext => (
400→                <ExtensionRow
401→                  key={ext.id}
402→                  ext={ext}
403→                  onToggle={onToggle}
404→                  showAuthor={false}
405→                />
406→              ))}
407→            </div>
408→          )}
409→          {communityExts.length > 0 && (
410→            <div className="settings-section">
411→              <div className="settings-section__title">Community</div>
412→              {communityExts.map(ext => (
413→                <ExtensionRow
414→                  key={ext.id}
415→                  ext={ext}
416→                  onToggle={onToggle}
417→                  showAuthor
418→                />
419→              ))}
420→            </div>
421→          )}
422→        </>
423→      )}
424→    </div>
425→  );
426→}
